"""
Minimal synchronous SoT using the OpenAI-compatible API.
Suitable for environments where asyncio is not available.
"""
import concurrent.futures
from anthropic import Anthropic

client = Anthropic()
MODEL = "claude-3-5-haiku-20241022"

def get_skeleton(question: str) -> list[str]:
    resp = client.messages.create(
        model=MODEL,
        max_tokens=300,
        messages=[{
            "role": "user",
            "content": (
                f"List the key points for answering this question as a numbered list. "
                f"One sentence each. End with [DONE].\nQuestion: {question}"
            )
        }],
    )
    import re
    return re.findall(r"\d+\.\s*(.+)", resp.content[0].text)

def expand(question: str, points: list[str], idx: int) -> str:
    outline = "\n".join(f"{i+1}. {pt}" for i, pt in enumerate(points))
    resp = client.messages.create(
        model=MODEL,
        max_tokens=400,
        messages=[{
            "role": "user",
            "content": (
                f"Question: {question}\nOutline:\n{outline}\n\n"
                f"Expand point {idx+1}: {points[idx]}"
            )
        }],
    )
    return resp.content[0].text.strip()

def sot_sync(question: str, max_workers: int = 5) -> str:
    points = get_skeleton(question)
    with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as ex:
        futures = {ex.submit(expand, question, points, i): i for i in range(len(points))}
        results = {f.result(): futures[f] for f in concurrent.futures.as_completed(futures)}
    ordered = [k for k, v in sorted(results.items(), key=lambda x: x[1])]
    return "\n\n".join(
        f"**{i+1}. {pt}**\n{exp}"
        for i, (pt, exp) in enumerate(zip(points, ordered))
    )

if __name__ == "__main__":
    print(sot_sync("What are the key differences between SQL and NoSQL databases?"))

# WRONG: passes raw skeleton text without extracting the current point
def expand_wrong(question, skeleton_text, idx):
    return llm(f"Expand the skeleton: {skeleton_text}")  # model ignores idx

# RIGHT: extract the specific point and pass both skeleton + point index
def expand_right(question, skeleton_text, points, idx):
    return llm(
        f"Question: {question}\nOutline:\n{skeleton_text}\n"
        f"Expand point {idx+1}: {points[idx]}"
    )

from langgraph.graph import StateGraph, END

def skeleton_node(state):
    points = get_skeleton(state["question"])
    return {"points": points, "expansions": {}}

def make_expand_node(idx):
    def expand_node(state):
        expansion = expand_point(state["question"], state["points"], idx)
        return {"expansions": {**state["expansions"], idx: expansion}}
    return expand_node

def stitch_node(state):
    ordered = [state["expansions"][i] for i in range(len(state["points"]))]
    return {"final": "\n\n".join(ordered)}

graph = StateGraph(dict)
graph.add_node("skeleton", skeleton_node)
for i in range(5):
    graph.add_node(f"expand_{i}", make_expand_node(i))
    graph.add_edge("skeleton", f"expand_{i}")
    graph.add_edge(f"expand_{i}", "stitch")
graph.add_node("stitch", stitch_node)
graph.add_edge("stitch", END)

async def validate_expansion(question, expansion, point_summary):
    resp = await client.messages.create(
        model=MODEL, max_tokens=100,
        messages=[{"role": "user", "content": (
            f"Does this expansion accurately address '{point_summary}'? "
            f"Reply YES or NO and a brief reason.\n\n{expansion}"
        )}],
    )
    return resp.content[0].text.strip()

async def safe_expand(question, skeleton, i, pt):
    try:
        return await expand_point(question, skeleton, i, pt)
    except Exception:
        return f"[Section {i+1} unavailable — please retry]"
